#include <stdio.h>
#include <stdlib.h>

// Define a structure for data points
typedef struct {
 int x;
 int y;
} DataPoint;

// Function to calculate the Euclidean distance between two points
float distance(DataPoint p1, DataPoint p2) {
 return sqrt(pow(p1.x - p2.x, 2) + pow(p1.y - p2.y, 2));
}

int main() {
 // Define data points
 DataPoint points[] = {{1, 2}, {2, 3}, {3, 5}, {4, 7}, {5, 11}};
 int n = sizeof(points) / sizeof(points[0]);

 // Calculate distances between points
 for (int i = 0; i < n; i++) {
 for (int j = i + 1; j < n; j++) {
 float dist = distance(points[i], points[j]);
 printf("Distance between points %d and %d: %f\n", i, j, dist);
 }
 }

 return 0;
}
